// Простой jQuery для совместимости
(function() {
    'use strict';
    
    // Простая реализация jQuery
    window.$ = window.jQuery = function(selector) {
        if (typeof selector === 'string') {
            return document.querySelectorAll(selector);
        } else if (selector instanceof Element) {
            return [selector];
        } else if (selector instanceof NodeList) {
            return selector;
        }
        return [];
    };
    
    // Основные методы jQuery
    $.extend = function(target, source) {
        for (let key in source) {
            if (source.hasOwnProperty(key)) {
                target[key] = source[key];
            }
        }
        return target;
    };
    
    $.ajax = function(options) {
        return fetch(options.url, {
            method: options.method || 'GET',
            headers: options.headers || {},
            body: options.data ? JSON.stringify(options.data) : undefined
        }).then(function(response) {
            if (options.dataType === 'json') {
                return response.json();
            }
            return response.text();
        }).then(function(data) {
            if (options.success) {
                options.success(data);
            }
        }).catch(function(error) {
            if (options.error) {
                options.error(error);
            }
        });
    };
    
    // Методы для элементов
    NodeList.prototype.each = function(callback) {
        for (let i = 0; i < this.length; i++) {
            callback.call(this[i], i, this[i]);
        }
        return this;
    };
    
    NodeList.prototype.on = function(event, handler) {
        this.each(function() {
            this.addEventListener(event, handler);
        });
        return this;
    };
    
    NodeList.prototype.off = function(event, handler) {
        this.each(function() {
            this.removeEventListener(event, handler);
        });
        return this;
    };
    
    NodeList.prototype.html = function(content) {
        if (content !== undefined) {
            this.each(function() {
                this.innerHTML = content;
            });
            return this;
        } else {
            return this[0] ? this[0].innerHTML : '';
        }
    };
    
    NodeList.prototype.text = function(content) {
        if (content !== undefined) {
            this.each(function() {
                this.textContent = content;
            });
            return this;
        } else {
            return this[0] ? this[0].textContent : '';
        }
    };
    
    NodeList.prototype.val = function(value) {
        if (value !== undefined) {
            this.each(function() {
                this.value = value;
            });
            return this;
        } else {
            return this[0] ? this[0].value : '';
        }
    };
    
    NodeList.prototype.addClass = function(className) {
        this.each(function() {
            this.classList.add(className);
        });
        return this;
    };
    
    NodeList.prototype.removeClass = function(className) {
        this.each(function() {
            this.classList.remove(className);
        });
        return this;
    };
    
    NodeList.prototype.toggleClass = function(className) {
        this.each(function() {
            this.classList.toggle(className);
        });
        return this;
    };
    
    NodeList.prototype.show = function() {
        this.each(function() {
            this.style.display = '';
        });
        return this;
    };
    
    NodeList.prototype.hide = function() {
        this.each(function() {
            this.style.display = 'none';
        });
        return this;
    };
    
    NodeList.prototype.fadeIn = function(duration) {
        this.each(function() {
            this.style.opacity = '0';
            this.style.display = '';
            setTimeout(() => {
                this.style.transition = `opacity ${duration || 300}ms`;
                this.style.opacity = '1';
            }, 10);
        });
        return this;
    };
    
    NodeList.prototype.fadeOut = function(duration) {
        this.each(function() {
            this.style.transition = `opacity ${duration || 300}ms`;
            this.style.opacity = '0';
            setTimeout(() => {
                this.style.display = 'none';
            }, duration || 300);
        });
        return this;
    };
    
})();
